func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	assignIndices := make([]int, MAXASSIGNS)
	activeLimit := 0
	for i := 0; i < dispatch.AssignsLen; i++ {
		assignIndices[i] = i
		if dispatch.Assigns[i].StationsLen > 0 {
			assignIndices[activeLimit], assignIndices[i] = assignIndices[i], assignIndices[activeLimit]
			activeLimit++
		}
	}
	for i := activeLimit; i < dispatch.AssignsLen; i++ {
		assignIndices[i] = i
	}
	totalConsidered := dispatch.AssignsLen
	if totalConsidered == 0 {
		totalConsidered = 1
		assignIndices[0] = 0
	}
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestAssignIdx := -1
		bestCostDelta := math.MaxFloat64
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		candidates := make([]int, totalConsidered)
		copy(candidates, assignIndices[:totalConsidered])
		for c := len(candidates) - 1; c > 0; c-- {
			j := rand.Intn(c + 1)
			candidates[c], candidates[j] = candidates[j], candidates[c]
		}
		for _, candIdx := range candidates {
			if candIdx >= MAXASSIGNS {
				continue
			}
			if candIdx >= dispatch.AssignsLen {
				if dispatch.AssignsLen >= MAXASSIGNS {
					continue
				}
				tempIdx := dispatch.AssignsLen
				dispatch.Assigns[tempIdx].StationCurrent = ori
				dispatch.Assigns[tempIdx].StationsLen = 0
				dispatch.Assigns[tempIdx].Cost = 0.0
				oldCost := dispatch.Assigns[tempIdx].Cost
				ok := dispatch.Assigns[tempIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[tempIdx].GenRoute()
					newCost := dispatch.Assigns[tempIdx].Cost
					delta := newCost - oldCost
					if delta < 0 || math.IsInf(delta, 0) || math.IsNaN(delta) {
						dispatch.Assigns[tempIdx].RemoveShip(shipID)
						dispatch.Assigns[tempIdx].GenRoute()
					} else {
						dispatch.AssignsLen++
						bestAssignIdx = tempIdx
						bestCostDelta = delta
						break
					}
				}
				continue
			}
			oldCost := dispatch.Assigns[candIdx].Cost
			savedState := dispatch.Assigns[candIdx]
			ok := dispatch.Assigns[candIdx].AddShip(shipID, ori, des)
			if !ok {
				dispatch.Assigns[candIdx].Cost = -1
			} else {
				dispatch.Assigns[candIdx].GenRoute()
			}
			if dispatch.Assigns[candIdx].Cost < 0 {
				dispatch.Assigns[candIdx] = savedState
				dispatch.Assigns[candIdx].GenRoute()
				continue
			}
			newCost := dispatch.Assigns[candIdx].Cost
			delta := newCost - oldCost
			dispatch.Assigns[candIdx] = savedState
			dispatch.Assigns[candIdx].GenRoute()
			if delta < bestCostDelta && delta >= 0 {
				bestCostDelta = delta
				bestAssignIdx = candIdx
			}
		}
		if bestAssignIdx == -1 {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx >= MAXASSIGNS {
				for ai := 0; ai < dispatch.AssignsLen; ai++ {
					saved := dispatch.Assigns[ai]
					if dispatch.Assigns[ai].AddShip(shipID, ori, des) {
						dispatch.Assigns[ai].GenRoute()
						if dispatch.Assigns[ai].Cost >= 0 {
							bestAssignIdx = ai
							break
						}
						dispatch.Assigns[ai] = saved
						dispatch.Assigns[ai].GenRoute()
					}
				}
				if bestAssignIdx == -1 {
					continue
				}
			} else {
				dispatch.Assigns[fallbackIdx].StationCurrent = ori
				dispatch.Assigns[fallbackIdx].StationsLen = 0
				dispatch.Assigns[fallbackIdx].Cost = 0.0
				if dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des) {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
						bestAssignIdx = fallbackIdx
					}
				}
				if bestAssignIdx == -1 {
					continue
				}
			}
		} else {
			retryOk := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if retryOk {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if dispatch.Assigns[bestAssignIdx].Cost < 0 {
					dispatch.Assigns[bestAssignIdx].RemoveShip(shipID)
					dispatch.Assigns[bestAssignIdx].GenRoute()
					fallbackIdx := dispatch.AssignsLen
